// ObserveOptions 配置 Observe 模式的行為
type ObserveOptions struct {
	// OutputPath 指定 HTML 報告的輸出路徑
	// 預設：.hyp/observe_YYYYMMDD_HHMMSS.html
	OutputPath string

	// OpenBrowser 生成報告後自動在瀏覽器開啟
	// macOS: open, Linux: xdg-open, Windows: start
	OpenBrowser bool

	// Silent 抑制 t.Logf 的報告路徑輸出
	Silent bool

	// Run 配置執行引擎（並行、重試、速率限制、FailFast）
	// 零值等同原有行為（循序、不重試、不限速、不 FailFast）
	Run RunConfig
}

// CapturedRequest 記錄實際發出的 HTTP 請求完整內容
type CapturedRequest struct {
	Method  string
	Path    string
	Headers map[string]string
	Body    string
}

// CapturedResponse 記錄實際收到的 HTTP 回應完整內容
type CapturedResponse struct {
	StatusCode int
	Headers    map[string]string
	Body       string
}

// ValidationStep 代表驗證鏈中的單一檢查項目
type ValidationStep struct {
	Name   string
	Pass   bool
	Detail string
}

// ObserveResult 為單一路由的完整觀察記錄
type ObserveResult struct {
	Route      schema.Route
	Request    CapturedRequest
	Response   CapturedResponse
	Steps      []ValidationStep
	Pass       bool
	FailReason string
	Duration   time.Duration
	Timestamp  time.Time

	// 資源/效能量測（記憶體、CPU、資源使用）。
	// 為避免全域取樣（ReadMemStats / 行程 CPU / 全域資源計數器）被並行請求互相污染，
	// 僅在「循序模式」量測；並行模式下 Measured=false，其餘量測欄位為零值。
	Measured   bool           // 是否實際量測（並行模式為 false）
	AllocBytes uint64         // 本次交換期間堆積配置位元組數（runtime TotalAlloc 差分）
	Allocs     uint64         // 本次交換期間配置次數（runtime Mallocs 差分）
	CPUTime    time.Duration  // 本次交換期間行程 CPU 時間差分（user+sys，行程層級近似）
	Resources  resource.Stats // 本次交換期間各資源（DB/Redis/Cassandra）存取次數差分
}

// ObserveAll 以觀察模式執行所有 schema-registered REST 路由的 contract 測試
// 捕捉每條路由的完整 HTTP 交換並生成 HTML 報告
//
// 用法：
//
//	func TestObserve(t *testing.T) {
//	    contract.ObserveAll(t, setupRouter())
//	}
//
//	func TestObserveWithBrowser(t *testing.T) {
//	    contract.ObserveAll(t, setupRouter(), contract.ObserveOptions{OpenBrowser: true})
//	}
//
//	func TestObserveParallel(t *testing.T) {
//	    contract.ObserveAll(t, setupRouter(), contract.ObserveOptions{
//	        Run: contract.RunConfig{Parallel: true, MaxWorkers: 4, RetryCount: 2},
//	    })
//	}
//
// @ai purpose: 觀察所有 schema-registered REST 路由，捕捉完整 HTTP 交換並生成 HTML 報告
// @ai input: *testing.T（可為 nil）、*hypRouter.Router、可選的 ObserveOptions
// @ai output: []ObserveResult（每條路由一筆完整記錄）
// @ai sideeffect: 建立 .hyp/ 目錄、寫入 HTML 報告、可開啟瀏覽器
// date: 2026-05-23
func ObserveAll(t *testing.T, r *hypRouter.Router, opts ...ObserveOptions) []ObserveResult {
	if t != nil {
		t.Helper()
	}
	return runObserve(t, r, "", mergeObserveOpts(opts))
}

// Observe 以觀察模式執行與 funcName 相關的路由 contract 測試
// funcName 會對路由的 HandlerNames、Path、Summary、Tags 做大小寫不敏感的子字串比對
// 空字串等同於 ObserveAll
//
// 用法：
//
//	func TestObserveCreateOrder(t *testing.T) {
//	    contract.Observe(t, setupRouter(), "createOrderHandler")
//	}
//
//	// 也可以用路徑片段或標籤過濾
//	func TestObserveOrders(t *testing.T) {
//	    contract.Observe(t, setupRouter(), "orders")
//	}
//
// @ai purpose: 依過濾條件觀察特定路由，支援 HandlerNames / Path / Summary / Tags 比對
// @ai input: *testing.T（可為 nil）、*hypRouter.Router、funcName string（過濾條件）、可選的 ObserveOptions
// @ai output: []ObserveResult（符合過濾條件的路由記錄）
// @ai sideeffect: 建立 .hyp/ 目錄、寫入 HTML 報告、可開啟瀏覽器
// date: 2026-05-23
func Observe(t *testing.T, r *hypRouter.Router, funcName string, opts ...ObserveOptions) []ObserveResult {
	if t != nil {
		t.Helper()
	}
	return runObserve(t, r, funcName, mergeObserveOpts(opts))
}

// runObserve 為 ObserveAll 和 Observe 的共用內部實作
// 支援循序與並行兩種執行路徑，均透過 writeObserveReport 輸出 HTML 報告
//
// @ai purpose: 整合路由過濾、執行引擎（RunConfig）、結果收集、HTML 報告寫入
// @ai input: *testing.T、*hypRouter.Router、filter string、ObserveOptions
// @ai output: []ObserveResult
// @ai sideeffect: 可能建立 .hyp/ 目錄並寫入 HTML 檔案
// date: 2026-05-23
func runObserve(t *testing.T, r *hypRouter.Router, filter string, opt ObserveOptions) []ObserveResult {
	routes := schema.Global().All()
	if len(routes) == 0 {
		if t != nil {
			t.Skip("no schema-registered routes found — SKIP")
		}
		return nil
	}

	// 過濾出符合條件的 REST 路由
	var targets []schema.Route
	for _, route := range routes {
		if !route.IsREST() {
			continue
		}
		if filter != "" && !observeRouteMatchesFilter(route, filter) {
			continue
		}
		targets = append(targets, route)
	}

	if len(targets) == 0 {
		if t != nil {
			t.Logf("[observe] no routes matched filter %q", filter)
		}
		return nil
	}

	cfg := opt.Run
	// 防禦性檢查：MaxWorkers 在 mergeObserveOpts 不做正規化，在此補齊
	if cfg.MaxWorkers <= 0 {
		cfg.MaxWorkers = runtime.GOMAXPROCS(0)
	}

	// ── 並行路徑 ──────────────────────────────────────────────────────────
	if cfg.Parallel && len(targets) > 1 {
		sem := make(chan struct{}, cfg.MaxWorkers)
		var (
			mu      sync.Mutex
			wg      sync.WaitGroup
			aborted atomic.Bool
			results []ObserveResult
		)

		// 速率限制器
		var limiterCh <-chan time.Time
		if cfg.RateLimit > 0 {
			ticker := time.NewTicker(time.Second / time.Duration(cfg.RateLimit))
			limiterCh = ticker.C
			defer ticker.Stop()
		}

		for _, route := range targets {
			if aborted.Load() {
				break
			}
			route := route // capture

			wg.Add(1)
			go func() {
				defer wg.Done()

				// 獲取 semaphore slot（控制最大並行數）
				sem <- struct{}{}
				defer func() { <-sem }()

				// 再次檢查：獲取 slot 後可能已有其他 goroutine 設定 FailFast
				if aborted.Load() {
					return
				}

				// 速率限制
				if cfg.RateLimit > 0 {
					<-limiterCh
				}

				result := captureWithRetry(r, route, cfg)

				mu.Lock()
				results = append(results, result)
				mu.Unlock()

				if !result.Pass && cfg.FailFast {
					aborted.Store(true)
				}
			}()
		}
		wg.Wait()

		return writeObserveReport(t, results, filter, opt)
	}

	// ── 循序路徑（預設）──────────────────────────────────────────────────
	var results []ObserveResult
	var seqAborted bool

	for _, route := range targets {
		if cfg.FailFast && seqAborted {
			break
		}
		// 循序速率限制：兩次執行間 sleep
		if cfg.RateLimit > 0 {
			time.Sleep(time.Second / time.Duration(cfg.RateLimit))
		}
		result := captureWithRetry(r, route, cfg)
		results = append(results, result)
		if !result.Pass && cfg.FailFast {
			seqAborted = true
		}
	}

	return writeObserveReport(t, results, filter, opt)
}

// captureWithRetry 執行帶重試機制的 captureRouteExchange
// 失敗時最多重試 cfg.RetryCount 次，回傳最後一次的完整記錄
//
// @ai purpose: 讓 Observe 模式也能受益於 RunConfig 的重試設定
// @ai input: *hypRouter.Router、schema.Route、RunConfig（重試設定）
// @ai output: ObserveResult（最後一次執行的完整記錄）
// @ai sideeffect: 無（不接觸 *testing.T）
// date: 2026-05-23
func captureWithRetry(r *hypRouter.Router, route schema.Route, cfg RunConfig) ObserveResult {
	// 僅循序模式量測資源/效能：並行時全域取樣會被其他請求污染
	measure := !cfg.Parallel
	var result ObserveResult
	for attempt := 0; attempt <= cfg.RetryCount; attempt++ {
		if attempt > 0 && cfg.RetryDelay > 0 {
			time.Sleep(cfg.RetryDelay)
		}
		result = captureRouteExchange(r, route, measure)
		if result.Pass {
			break
		}
	}
	return result
}

// writeObserveReport 將結果列表寫入 HTML 報告並回傳結果
// 提取為獨立函式以消除循序/並行兩條路徑的重複邏輯
//
// @ai purpose: 統一處理 HTML 報告生成、檔案寫入、瀏覽器開啟
// @ai input: *testing.T（可為 nil）、[]ObserveResult、filter string、ObserveOptions
// @ai output: []ObserveResult（原樣回傳，供呼叫端程式化斷言）
// @ai sideeffect: 建立 .hyp/ 目錄、寫入 HTML 檔案、可開啟瀏覽器
// date: 2026-05-23
func writeObserveReport(t *testing.T, results []ObserveResult, filter string, opt ObserveOptions) []ObserveResult {
	if len(results) == 0 {
		return results
	}

	outPath := opt.OutputPath
	if outPath == "" {
		if err := os.MkdirAll(".hyp", 0o755); err == nil {
			ts := time.Now().Format("20060102_150405")
			outPath = filepath.Join(".hyp", fmt.Sprintf("observe_%s.html", ts))
		}
	}
	if outPath != "" {
		htmlContent := GenerateObserveHTML(results, filter)
		if err := os.WriteFile(outPath, []byte(htmlContent), 0o644); err == nil {
			if t != nil && !opt.Silent {
				t.Logf("[observe] report → %s", outPath)
			}
			if opt.OpenBrowser {
				openObserveBrowser(outPath)
			}
		}
	}

	return results
}

// captureRouteExchange 執行一條路由的測試並捕捉完整的 HTTP 交換記錄
//
// @ai purpose: 捕捉單一路由的完整 HTTP 請求/回應、執行四步驗證，並量測資源/效能消耗
// @ai input: *hypRouter.Router、schema.Route、measure（是否量測記憶體/CPU/資源，循序模式為 true）
// @ai output: ObserveResult（含完整 HTTP 交換記錄、驗證步驟與資源/效能量測）
// @ai sideeffect: 無（httptest 模式，不開真實 port）；measure 時呼叫 runtime.ReadMemStats（STW）
// date: 2026-05-23
// @ai:modified by=claude-opus-4-8 date=2026-06-15 reason=新增記憶體/CPU/資源使用量測（measure 參數）
func captureRouteExchange(r *hypRouter.Router, route schema.Route, measure bool) ObserveResult {
	tc := generateTestCase(route)
	tc.schemaPath = route.Path

	// 解析 Route 字串（格式："METHOD /path"）
	method, urlPath := parseRoute(tc.Route)

	// 建立請求
	req := httptest.NewRequest(method, urlPath, strings.NewReader(tc.Input))
	if tc.Input != "" {
		req.Header.Set("Content-Type", "application/json")
	}
	for k, v := range tc.Headers {
		req.Header.Set(k, v)
	}
	if len(tc.Query) > 0 {
		q := req.URL.Query()
		for k, v := range tc.Query {
			q.Set(k, v)
		}
		req.URL.RawQuery = q.Encode()
	}

	// 捕捉請求詳情
	capturedReq := CapturedRequest{
		Method:  method,
		Path:    req.URL.RequestURI(),
		Body:    tc.Input,
		Headers: make(map[string]string),
	}
	for k, v := range req.Header {
		capturedReq.Headers[k] = strings.Join(v, ", ")
	}

	// 量測基準（僅循序模式；並行模式全域取樣會被互相污染）
	var memBefore runtime.MemStats
	var cpuBefore time.Duration
	var resBefore resource.Stats
	if measure {
		resBefore = resource.Snapshot()
		runtime.ReadMemStats(&memBefore)
		cpuBefore = processCPUTime()
	}

	// 執行請求（計時僅涵蓋 handler 執行，排除上方量測取樣的開銷）
	w := httptest.NewRecorder()
	reqStart := time.Now()
	r.ServeHTTP(w, req)
	dur := time.Since(reqStart)

	var (
		measured   bool
		allocBytes uint64
		allocs     uint64
		cpuUsed    time.Duration
		resUsed    resource.Stats
	)
	if measure {
		var memAfter runtime.MemStats
		runtime.ReadMemStats(&memAfter)
		cpuUsed = processCPUTime() - cpuBefore
		resUsed = resource.Snapshot().Sub(resBefore)
		allocBytes = memAfter.TotalAlloc - memBefore.TotalAlloc
		allocs = memAfter.Mallocs - memBefore.Mallocs
		measured = true
	}

	// 捕捉回應詳情
	respBody := w.Body.Bytes()
	capturedResp := CapturedResponse{
		StatusCode: w.Code,
		Body:       string(respBody),
		Headers:    make(map[string]string),
	}
	for k, v := range w.Header() {
		capturedResp.Headers[k] = strings.Join(v, ", ")
	}

	// 逐步驗證
	steps, pass, failReason := runObserveValidation(route, tc, w.Code, respBody)

	return ObserveResult{
		Route:      route,
		Request:    capturedReq,
		Response:   capturedResp,
		Steps:      steps,
		Pass:       pass,
		FailReason: failReason,
		Duration:   dur,
		Timestamp:  time.Now(),
		Measured:   measured,
		AllocBytes: allocBytes,
		Allocs:     allocs,
		CPUTime:    cpuUsed,
		Resources:  resUsed,
	}
}

// runObserveValidation 逐步執行驗證並記錄每個步驟的結果
//
// @ai purpose: 四步驗證（狀態碼、回應 body 非空、Input schema、Output schema）
// @ai input: schema.Route、TestCase（自動生成）、實際 HTTP 狀態碼、回應 body
// @ai output: []ValidationStep、pass bool、reason string
// @ai sideeffect: 無
// date: 2026-05-23
func runObserveValidation(route schema.Route, tc TestCase, code int, body []byte) (steps []ValidationStep, pass bool, reason string) {
	pass = true

	// Step 1：狀態碼
	wantStatus := tc.ExpectStatus
	statusOK := code == wantStatus
	steps = append(steps, ValidationStep{
		Name:   "Status Code",
		Pass:   statusOK,
		Detail: fmt.Sprintf("got %d, want %d", code, wantStatus),
	})
	if !statusOK {
		pass = false
		reason = fmt.Sprintf("status = %d, want %d", code, wantStatus)
	}

	// Step 2：回應 body 非空（有 Output schema 時）
	if route.Output != nil {
		bodyOK := len(bytes.TrimSpace(body)) > 0
		steps = append(steps, ValidationStep{
			Name:   "Response Body",
			Pass:   bodyOK,
			Detail: observeIfElse(bodyOK, "body present", "body is empty"),
		})
		if !bodyOK && pass {
			pass = false
			reason = "response body is empty"
		}
	}

	// Step 3：Input schema 驗證
	if route.Input != nil && tc.Input != "" {
		err := validateRequest([]byte(tc.Input), route.Input)
		inputOK := err == nil
		var inputDetail string
		if inputOK {
			inputDetail = "matches schema"
		} else {
			inputDetail = err.Error()
		}
		steps = append(steps, ValidationStep{
			Name:   fmt.Sprintf("Input Schema (%s)", route.InputName),
			Pass:   inputOK,
			Detail: inputDetail,
		})
	}

	// Step 4：Output schema 驗證
	if route.Output != nil && len(bytes.TrimSpace(body)) > 0 {
		err := validateResponse(body, route.Output)
		outOK := err == nil
		var outDetail string
		if outOK {
			outDetail = "matches schema"
		} else {
			outDetail = err.Error()
		}
		steps = append(steps, ValidationStep{
			Name:   fmt.Sprintf("Output Schema (%s)", route.OutputName),
			Pass:   outOK,
			Detail: outDetail,
		})
		if !outOK && pass {
			pass = false
			reason = err.Error()
		}
	}

	return
}

// observeRouteMatchesFilter 判斷路由是否符合過濾字串
// 對 HandlerNames、Path、Summary、Tags 做大小寫不敏感的子字串比對
//
// @ai purpose: 讓 Observe(t, r, "funcName") 可以依多個維度過濾路由
// @ai input: schema.Route、filter string
// @ai output: bool（是否符合）
// @ai sideeffect: 無
// date: 2026-05-23
func observeRouteMatchesFilter(route schema.Route, filter string) bool {
	f := strings.ToLower(filter)
	for _, h := range route.HandlerNames {
		if strings.Contains(strings.ToLower(h), f) {
			return true
		}
	}
	if strings.Contains(strings.ToLower(route.Path), f) {
		return true
	}
	if strings.Contains(strings.ToLower(route.Summary), f) {
		return true
	}
	for _, tag := range route.Tags {
		if strings.Contains(strings.ToLower(tag), f) {
			return true
		}
	}
	return false
}

// mergeObserveOpts 取第一個 ObserveOptions 或回傳預設值
//
// @ai purpose: 讓 ObserveAll(t, r) 零引數呼叫繼續向後相容
// @ai input: []ObserveOptions
// @ai output: ObserveOptions（第一個或零值）
// @ai sideeffect: 無
// date: 2026-05-23
func mergeObserveOpts(opts []ObserveOptions) ObserveOptions {
	if len(opts) > 0 {
		return opts[0]
	}
	return ObserveOptions{}
}

// observeIfElse 為內部使用的三元表達式替代
//
// @ai purpose: 消除 if/else 的樣板程式碼
// @ai input: cond bool、t string（true 時回傳）、f string（false 時回傳）
// @ai output: string
// @ai sideeffect: 無
// date: 2026-05-23
func observeIfElse(cond bool, t, f string) string {
	if cond {
		return t
	}
	return f
}

// openObserveBrowser 在預設瀏覽器中開啟指定路徑的 HTML 報告
//
// @ai purpose: 跨平台開啟瀏覽器（macOS / Linux / Windows）
// @ai input: path string（HTML 報告的相對或絕對路徑）
// @ai output: 無
// @ai sideeffect: 啟動系統瀏覽器程序
// date: 2026-05-23
func openObserveBrowser(path string) {
	abs, err := filepath.Abs(path)
	if err != nil {
		abs = path
	}
	url := "file://" + filepath.ToSlash(abs)
	switch runtime.GOOS {
	case "darwin":
		exec.Command("open", url).Start() //nolint:errcheck
	case "linux":
		exec.Command("xdg-open", url).Start() //nolint:errcheck
	case "windows":
		exec.Command("cmd", "/c", "start", "", url).Start() //nolint:errcheck
	}
}
